using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ───────────────────────────────────────────────
    //  CalculateTotal – DataRow (compile-time constants)
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 10, 0.10, 0.00, DisplayName = "Zero unit price")]
    [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    [DataRow(100.00, 2, 1.0, 400.00, DisplayName = "Maximum tax rate (100%)")]
    [DataRow(0.01, 1, 0.0, 0.01, DisplayName = "Smallest meaningful price")]
    public void CalculateTotal_WithDataRow_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ───────────────────────────────────────────────
    //  CalculateTotal – DynamicData (complex/decimal-precise scenarios)
    // ───────────────────────────────────────────────

    public static IEnumerable<object[]> CalculateTotalScenarios
    {
        get
        {
            // High-volume order
            yield return new object[] { 5.00m, 1000, 0.07m, 5350.00m, "Bulk order with 7% tax" };
            // Sub-cent precision
            yield return new object[] { 9.99m, 3, 0.065m, 31.92105m, "Tax rate with fractional percent" };
            // Large unit price
            yield return new object[] { 9999.99m, 1, 0.0m, 9999.99m, "Expensive item, no tax" };
            // Combination of ones
            yield return new object[] { 1.00m, 1, 0.0m, 1.00m, "All unit values" };
        }
    }

    [TestMethod]
    [DynamicData(nameof(CalculateTotalScenarios))]
    public void CalculateTotal_WithDynamicData_ReturnsExpected(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected, string scenario)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result, $"Failed for scenario: {scenario}");
    }

    // ───────────────────────────────────────────────
    //  CalculateTotal – invalid inputs
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, DisplayName = "Negative unit price")]
    public void CalculateTotal_NegativeUnitPrice_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity")]
    public void CalculateTotal_NegativeQuantity_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, 1, -0.01, DisplayName = "Tax rate below zero")]
    [DataRow(10.00, 1, 1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_InvalidTaxRate_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    // ───────────────────────────────────────────────
    //  ApplyDiscount – DataRow
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(100.00, 0.0, 100.00, DisplayName = "No discount")]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% discount")]
    [DataRow(100.00, 50.0, 50.00, DisplayName = "50% discount")]
    [DataRow(100.00, 100.0, 0.00, DisplayName = "100% discount (free)")]
    [DataRow(49.99, 25.0, 37.4925, DisplayName = "Fractional result")]
    [DataRow(0.00, 50.0, 0.00, DisplayName = "Zero price, any discount")]
    [DataRow(200.00, 33.33, 133.34, DisplayName = "Repeating decimal discount")]
    public void ApplyDiscount_WithDataRow_ReturnsExpected(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // ───────────────────────────────────────────────
    //  ApplyDiscount – DynamicData (method source)
    // ───────────────────────────────────────────────

    public static IEnumerable<object[]> DiscountEdgeCases()
    {
        yield return new object[] { 999.99m, 0.01m, 999.890001m, "Tiny discount on large price" };
        yield return new object[] { 0.01m, 99.99m, 0.000001m, "Near-total discount on penny" };
        yield return new object[] { 1000.00m, 15.0m, 850.00m, "Standard 15% loyalty discount" };
    }

    [TestMethod]
    [DynamicData(nameof(DiscountEdgeCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_WithDynamicData_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected, string scenario)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result, $"Failed for scenario: {scenario}");
    }

    // ───────────────────────────────────────────────
    //  ApplyDiscount – invalid inputs
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(100.00, -1.0, DisplayName = "Negative discount")]
    [DataRow(100.00, 100.01, DisplayName = "Discount exceeds 100%")]
    public void ApplyDiscount_InvalidDiscountPercent_Throws(
        double price, double discountPercent)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent));
    }

    // ───────────────────────────────────────────────
    //  FormatPrice – DataRow
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(9.99, "$", "$9.99", DisplayName = "Dollar sign default")]
    [DataRow(1234.50, "€", "€1234.50", DisplayName = "Euro symbol")]
    [DataRow(0.00, "$", "$0.00", DisplayName = "Zero price")]
    [DataRow(1.1, "£", "£1.10", DisplayName = "Pads to two decimals")]
    [DataRow(99.999, "$", "$100.00", DisplayName = "Rounds to two decimals")]
    public void FormatPrice_WithDataRow_ReturnsExpected(
        double price, string currencySymbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, currencySymbol);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatPrice_DefaultCurrencySymbol_UsesDollarSign()
    {
        var result = _calculator.FormatPrice(42.00m);

        Assert.AreEqual("$42.00", result);
    }
}

